      // 本卡聊天活跃
      if (!ballExists) {
        log('syncMount: 本卡聊天(chatId=' + chatId + ')活跃,挂载球');
        setTimeout(mount, 50);
      } else {
        // 球已存在 → hash 校验
        var data = getStatData();
        if (data) {
          try {
            var hash = JSON.stringify(data);
            if (hash !== lastDataHash) { lastDataHash = hash; render(); }
          } catch (e) {}
        }
      }
    } catch (e) {
      try { GS_PARENT.console.warn('[HX-Float] syncMount 异常', e && e.message); } catch (e2) {}
    }
  }

  // 「破解模式」状态 — 开启时允许强行修改只读字段/对象/数值
  // 状态写入 MVU 的 stat_data.__hx_hack_mode(持久化跨对话) + localStorage(快速读取)
  function getHackMode() {
    try {
      var ls = GS_PARENT.localStorage && GS_PARENT.localStorage.getItem('hx_hack_mode');
      if (ls === '1') return true;
      var d = getStatData();
      if (d && d.__hx_hack_mode === true) return true;
    } catch (e) {}
    return false;
  }
  function setHackMode(on) {
    try { if (GS_PARENT.localStorage) GS_PARENT.localStorage.setItem('hx_hack_mode', on ? '1' : '0'); } catch (e) {}
    try { setVar('__hx_hack_mode', on ? true : false); } catch (e) {}
  }

  // 「关闭聊天」信号独立处理 — Tavern 此时 CHAT_CHANGED payload 为 undefined;
  // 但 QR2 模块传给 onChatChanged 的 payload 实际经常是字符串/undefined 不一,
  // 统一走 syncMount 让 syncMount 内部基于 getContext 真实数据判断
  function onChatChanged(payload) {
    try { log('CHAT_CHANGED 触发, payload type=' + (typeof payload) + ', val=' + (typeof payload === 'string' ? payload.slice(0, 60) : String(payload).slice(0, 60))); } catch (e) {}
    // 关闭聊天信号(payload=undefined):酒馆切回角色列表/欢迎页时,立即卸球
    if (typeof payload === 'undefined' || payload === null) {
      if (doc.getElementById('hx-stat-ball')) {
        log('CHAT_CHANGED=undefined → 立即卸球');
        unmount();
      }
    }
    // 统一走 syncMount 让 syncMount 内部基于 getContext 真实数据判断(重新挂球/切角色判断)
    setTimeout(syncMount, 80);
  }

  // ===== 6. 启动 =====
  function bindMvuListener() {
    try {
      var mvu = getMvu();
      if (!mvu || !mvu.events || !mvu.events.VARIABLE_UPDATE_ENDED) return false;
      var evt = mvu.events.VARIABLE_UPDATE_ENDED;
      // 优先 GS_PARENT.eventOn(注入到主窗口作用域),次之当前 iframe 内
      var eon = (typeof GS_PARENT.eventOn === 'function') ? GS_PARENT.eventOn : (typeof eventOn === 'function' ? eventOn : null);
      if (eon) { eon(evt, debouncedRender); return true; }
    } catch (e) {}
    return false;
  }

  function init() {
    log('init 开始');
    try {
      log('init: GS_PARENT===window.parent=' + (GS_PARENT === window.parent) + ', body=' + !!doc.body + ', ST.getContext=' + (typeof (GS_PARENT.SillyTavern && GS_PARENT.SillyTavern.getContext)));
    } catch (e) {}
    if (!doc.body) {
      var wait = setInterval(function () {
        if (doc.body) { clearInterval(wait); init(); }
      }, 200);
      setTimeout(function () { clearTimeout(wait); clearInterval(wait); }, 10000);
      return;
    }
    // 无条件主动挂球,不依赖 getContext 判断(避免 init 时上下文未就绪导致静默不挂)
    if (!doc.getElementById('hx-stat-ball')) {
      log('init: 主动挂载球');
      setTimeout(mount, 50);
    } else {
      log('init: 球已存在,跳过初次挂载');
    }
    // 监听 MVU 变量更新(初次可能未就绪,2s 后再补一次)
    if (bindMvuListener()) log('已监听 VARIABLE_UPDATE_ENDED');
    else log('MVU 事件对象未就绪,2s 后重试');
    setTimeout(function () {
      if (bindMvuListener()) log('补监听 VARIABLE_UPDATE_ENDED 成功');
    }, 2000);
    // 监听酒馆事件
    try {
      if (typeof tavern_events !== 'undefined') {
        var eon = (typeof GS_PARENT.eventOn === 'function') ? GS_PARENT.eventOn : (typeof eventOn === 'function' ? eventOn : null);
        if (eon) {
          if (tavern_events.CHAT_CHANGED) eon(tavern_events.CHAT_CHANGED, onChatChanged);
          if (tavern_events.MESSAGE_DELETED) eon(tavern_events.MESSAGE_DELETED, debouncedRender);
          if (tavern_events.MESSAGE_SWIPED) eon(tavern_events.MESSAGE_SWIPED, debouncedRender);
        }
      }
    } catch (e) {}
    // 兜底轮询(3s):负责"切到其他角色"卸球 + 数据变更刷新
    setInterval(syncMount, 3000);
    try { GS_PARENT.__悬浮球状态栏_loaded__ = true; } catch (e) { window.__悬浮球状态栏_loaded__ = true; }
  }

  if (document.readyState === 'loading') {
    document.addEventListener('DOMContentLoaded', init);
  } else {
    init();
  }
})();

entries.content:
variables_update_rules:
  全局:
    只读字段: [/主角状态/最终属性]
    通用约束: [更新字段能增量就不全量, 数值超range按上下限截断]
    缺省原则: 数值类属性默认仅生成非0属性，未生成属性一律视为0
  环境与系统:
    当前时间: { check: [每楼必须推演时间合理流逝(上午→中午→下午…)，说明跳跃原因] }
    当前楼层: { check: [仅{{user}}移动到不同楼层时更改] }
    当前场景: { check: [据所在位置更新(办公室/食堂/健身房/天台/会议室/厕所等)] }
    当前位置: { check: [据具体场所更新(个人办公区/电梯/大厅/咖啡机/走廊等)，只描述当前场所] }
    公司氛围: { check: [随时间与事件变化] }
    活跃事件: { check: [事件发生时更新为事件名，结束回"无"] }
  主角状态:
    贡献点: { type: number, check: [消耗必精确扣减，获取必增加；余额不足时操作被拒，不得扣减；破解模式开启时锁∞] }
    精神状态: { type: number, range: 0~100, check: [惊悚/囚禁/暴力扣减，休息/正面互动恢复] }
    个人金钱: { type: number, check: [消费扣减，收入增加] }
    催眠权限等级: { type: number, check: [职级提升时自动提升：正式1/副组长2/组长3/副总监4/总监5] }
    破解模式: { type: boolean, check: [默认false；开启后忽略贡献点/职级/权限，贡献点显示∞] }
    已解锁成就: { type: array, check: [达成时添加，附带贡献点奖励] }
  助理管理:
    实习助理.${名} / 正式助理.${名} / 组长助理.${名}:
      在场: { check: [进入或离开视线时更新] }
      状态: { check: [更新当前行为(站立办公/培训中/执行催眠指令/剧本运行中等)] }
      情绪: { check: [每楼据互动推演情绪变化] }
      催眠状态: { check: [被催眠时更新为具体指令名，解除后回"未被催眠"] }
      三围/罩杯/改造状态: { check: [身体改造后更新] }
      好感度: { type: number, range: -100~100, check: [互动正向增、负向减] }
  催眠系统:
    当前剧本: { check: [启动剧本时更新为名，结束回"无"] }
    剧本消耗累计: { type: number, check: [每次启动剧本累加消耗贡献点] }
    可用剧本: { type: array, check: [据在场助理动态计算可参与列表] }
  隐藏场景:
    已发现: { type: array, check: [探索到新场景时添加] }
    当前探索: { check: [正在探索的场景名，无则"无"] }
  剧情进度:
    当前阶段: { check: [据职级与行动推进] }
    已触发事件: { type: array, check: [每次触发事件追加] }
